# ----------------------------
# Utilities: URL validation & SSRF hardening
# ----------------------------

PRIVATE_NETS = [
    re.compile(r"^10\..*"),
    re.compile(r"^127\..*"),
    re.compile(r"^169\.254\..*"),
    re.compile(r"^172\.(1[6-9]|2\d|3[0-1])\..*"),
    re.compile(r"^192\.168\..*"),
    re.compile(r"^0\..*"),
    re.compile(r"^255\.255\.255\.255$"),
]

LOCALHOST_NAMES = {"localhost", "localhost.localdomain"}


def _is_private_host(host: str) -> bool:
    host = (host or "").strip().lower()
    if not host:
        return True
    if host in LOCALHOST_NAMES:
        return True
    if host.endswith(".local"):
        return True
    # crude IP check
    if re.fullmatch(r"\d{1,3}(\.\d{1,3}){3}", host):
        for pat in PRIVATE_NETS:
            if pat.match(host):
                return True
        parts = host.split(".")
        try:
            if any(int(p) > 255 for p in parts):
                return True
        except ValueError:
            return True
    return False


def normalize_url(raw: str) -> str:
    raw = (raw or "").strip()
    if not raw:
        raise ValueError("empty_url")
    if len(raw) > MAX_URL_LENGTH:
        raise ValueError("url_too_long")

    parsed = urlparse(raw)
    if not parsed.scheme:
        # default to https if scheme missing
        parsed = urlparse("https://" + raw)

    scheme = parsed.scheme.lower()
    if scheme not in ALLOWED_SCHEMES:
        raise ValueError("unsupported_scheme")

    # Remove fragments
    parsed = parsed._replace(fragment="")

    # Normalize netloc and path
    netloc = parsed.netloc
    if not netloc:
        raise ValueError("missing_host")
    hostname = parsed.hostname or ""
    if not ALLOW_PRIVATE_IPS and _is_private_host(hostname):
        raise ValueError("private_host_not_allowed")

    # Keep port if specified
    # Rebuild URL
    normalized = urlunparse((
        scheme,
        netloc,
        parsed.path or "/",
        parsed.params or "",
        parsed.query or "",
        ""
    ))
    return normalized


def url_to_key(url: str) -> str:
    h = hashlib.sha256(url.encode("utf-8")).hexdigest()[:32]
    return f"{S3_PREFIX}{h}.{ 'jpg' if THUMB_FORMAT == 'jpeg' else 'png' }"


