boto_cfg = BotoConfig(retries={"max_attempts": 8, "mode": "standard"})
s3 = boto3.client("s3", region_name=AWS_REGION, config=boto_cfg)


def s3_put_object(key: str, body: bytes, content_type: str, meta: Dict[str, str]) -> None:
    extra = {}
    if S3_ACL:
        extra["ACL"] = S3_ACL
    if S3_KMS_KEY_ID:
        extra["ServerSideEncryption"] = "aws:kms"
        extra["SSEKMSKeyId"] = S3_KMS_KEY_ID

    s3.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=body,
        ContentType=content_type,
        CacheControl=f"public, max-age={DEDUP_TTL_SECONDS}" if S3_ACL == "public-read" else f"max-age={DEDUP_TTL_SECONDS}",
        Metadata=meta,
        **extra
    )


def s3_head_object(key: str) -> Optional[Dict[str, Any]]:
    try:
        return s3.head_object(Bucket=S3_BUCKET, Key=key)
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code", "")
        if code in ("404", "NoSuchKey", "NotFound"):
            return None
        raise


def s3_presign_get(key: str, expires: int = 3600) -> str:
    return s3.generate_presigned_url(
        "get_object",
        Params={"Bucket": S3_BUCKET, "Key": key},
        ExpiresIn=expires
    )


# ----------------------------
# Image processing
# ----------------------------

def make_thumbnail(image_bytes: bytes) -> Tuple[bytes, str]:
    with Image.open(io.BytesIO(image_bytes)) as im:
        im = im.convert("RGB") if THUMB_FORMAT == "jpeg" else im.convert("RGBA")

        # Center-crop to aspect ratio
        target_ratio = THUMB_WIDTH / THUMB_HEIGHT
        w, h = im.size
        src_ratio = w / h if h else 1.0

        if src_ratio > target_ratio:
            # too wide: crop width
            new_w = int(h * target_ratio)
            left = (w - new_w) // 2
            im = im.crop((left, 0, left + new_w, h))
        else:
            # too tall: crop height
            new_h = int(w / target_ratio)
            top = (h - new_h) // 2
            im = im.crop((0, top, w, top + new_h))

        im = im.resize((THUMB_WIDTH, THUMB_HEIGHT), Image.LANCZOS)

        out = io.BytesIO()
        if THUMB_FORMAT == "jpeg":
            im.save(out, format="JPEG", quality=THUMB_JPEG_QUALITY, optimize=True, progressive=True)
            return out.getvalue(), "image/jpeg"
        else:
            im.save(out, format="PNG", optimize=True)
            return out.getvalue(), "image/png"


