def build_chrome_driver() -> webdriver.Chrome:
    options = Options()
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-default-apps")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--disable-notifications")
    options.add_argument("--window-size=%d,%d" % (WINDOW_WIDTH, WINDOW_HEIGHT))
    options.add_argument(f"--user-agent={USER_AGENT}")
    options.add_argument("--lang=en-US,en")
    options.add_experimental_option("excludeSwitches", ["enable-automation"])
    options.add_experimental_option("useAutomationExtension", False)

    if CHROME_BINARY:
        options.binary_location = CHROME_BINARY

    service_kwargs = {}
    if CHROMEDRIVER_PATH:
        from selenium.webdriver.chrome.service import Service
        service = Service(executable_path=CHROMEDRIVER_PATH)
        driver = webdriver.Chrome(service=service, options=options)
    else:
        driver = webdriver.Chrome(options=options)

    driver.set_page_load_timeout(PAGELOAD_TIMEOUT_SECONDS)
    if IMPLICIT_WAIT_SECONDS > 0:
        driver.implicitly_wait(IMPLICIT_WAIT_SECONDS)

    try:
        driver.execute_cdp_cmd("Page.addScriptToEvaluateOnNewDocument", {
            "source": """
                Object.defineProperty(navigator, 'webdriver', {get: () => undefined});
            """
        })
    except Exception:
        pass

    return driver


def render_screenshot_png(url: str) -> bytes:
    driver = None
    try:
        driver = build_chrome_driver()
        driver.get(url)

        # Let above-the-fold stabilize
        time.sleep(0.8)

        # Best-effort: dismiss cookie banners by pressing Escape
        try:
            body = driver.find_element(By.TAG_NAME, "body")
            body.send_keys("\ue00c")  # ESC
        except Exception:
            pass

        time.sleep(0.4)

        if FULLPAGE:
            try:
                metrics = driver.execute_cdp_cmd("Page.getLayoutMetrics", {})
                content_size = metrics.get("contentSize", {})
                width = int(content_size.get("width", WINDOW_WIDTH))
                height = int(content_size.get("height", WINDOW_HEIGHT))
                width = max(320, min(width, 2000))
                height = max(240, min(height, 8000))
                driver.set_window_size(width, height)
                time.sleep(0.3)
            except Exception:
                pass

        png = driver.get_screenshot_as_png()
        return png
    except TimeoutException as e:
        raise RuntimeError("page_load_timeout") from e
    except WebDriverException as e:
        raise RuntimeError("webdriver_error") from e
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass


# ----------------------------
# Job Queue
# ----------------------------

@dataclass
class Job:
    job_id: str
    url: str
    key: str
    created_at: float


jobs_q: "queue.Queue[Job]" = queue.Queue(maxsize=JOB_QUEUE_MAX)
results: Dict[str, Dict[str, Any]] = {}
results_lock = threading.Lock()


def set_result(job_id: str, data: Dict[str, Any]) -> None:
    with results_lock:
        results[job_id] = data


def get_result(job_id: str) -> Optional[Dict[str, Any]]:
    with results_lock:
        return results.get(job_id)


def worker_loop(worker_id: int) -> None:
    while True:
        job = jobs_q.get()
        try:
            start = time.time()
            png = render_screenshot_png(job.url)
            thumb_bytes, content_type = make_thumbnail(png)
            meta = {"url": job.url, "job_id": job.job_id}

            s3_put_object(job.key, thumb_bytes, content_type, meta)

            elapsed = time.time() - start
            set_result(job.job_id, {
                "status": "done",
                "job_id": job.job_id,
                "url": job.url,
                "s3_key": job.key,
                "elapsed_seconds": round(elapsed, 3),
                "completed_at": time.time(),
            })
        except Exception as e:
            logger.exception("worker_failed worker_id=%s job_id=%s url=%s", worker_id, job.job_id, job.url)
            set_result(job.job_id, {
                "status": "error",
                "job_id": job.job_id,
                "url": job.url,
                "error": str(e),
                "completed_at": time.time(),
            })
        finally:
            jobs_q.task_done()


def start_workers() -> None:
    for i in range(WORKER_THREADS):
        t = threading.Thread(target=worker_loop, args=(i,), daemon=True)
        t.start()


