app = Flask(__name__)


@app.get("/health")
def health():
    return jsonify({
        "ok": True,
        "bucket_configured": bool(S3_BUCKET),
        "workers": WORKER_THREADS,
        "queue_size": jobs_q.qsize(),
    })


@app.post("/v1/screenshot")
def create_screenshot():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET_not_configured"}), 500

    payload = request.get_json(silent=True) or {}
    raw_url = payload.get("url") or request.args.get("url") or ""
    try:
        url = normalize_url(raw_url)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    key = url_to_key(url)

    head = s3_head_object(key)
    if head:
        if S3_ACL == "public-read" and PUBLIC_BASE_URL:
            public_url = PUBLIC_BASE_URL.rstrip("/") + "/" + key
            return jsonify({
                "status": "done",
                "url": url,
                "s3_key": key,
                "public_url": public_url,
                "cached": True,
            })
        return jsonify({
            "status": "done",
            "url": url,
            "s3_key": key,
            "download_url": s3_presign_get(key, expires=3600),
            "cached": True,
        })

    job_id = str(uuid.uuid4())
    job = Job(job_id=job_id, url=url, key=key, created_at=time.time())

    try:
        jobs_q.put(job, timeout=0.25)
    except queue.Full:
        return jsonify({"error": "queue_full"}), 429

    set_result(job_id, {
        "status": "queued",
        "job_id": job_id,
        "url": url,
        "s3_key": key,
        "created_at": job.created_at,
    })

    return jsonify({
        "status": "queued",
        "job_id": job_id,
        "url": url,
        "s3_key": key,
        "result_url": f"/v1/result/{job_id}",
    }), 202


@app.get("/v1/result/<job_id>")
def get_job_result(job_id: str):
    res = get_result(job_id)
    if not res:
        return jsonify({"error": "not_found"}), 404

    if res.get("status") == "done":
        key = res.get("s3_key", "")
        if S3_ACL == "public-read" and PUBLIC_BASE_URL:
            res = dict(res)
            res["public_url"] = PUBLIC_BASE_URL.rstrip("/") + "/" + key
        else:
            res = dict(res)
            res["download_url"] = s3_presign_get(key, expires=3600)
    return jsonify(res)


@app.post("/v1/screenshot_sync")
def screenshot_sync():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET_not_configured"}), 500

    payload = request.get_json(silent=True) or {}
    raw_url = payload.get("url") or request.args.get("url") or ""
    try:
        url = normalize_url(raw_url)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    key = url_to_key(url)

    head = s3_head_object(key)
    if head:
        if S3_ACL == "public-read" and PUBLIC_BASE_URL:
            public_url = PUBLIC_BASE_URL.rstrip("/") + "/" + key
            return jsonify({
                "status": "done",
                "url": url,
                "s3_key": key,
                "public_url": public_url,
                "cached": True,
            })
        return jsonify({
            "status": "done",
            "url": url,
            "s3_key": key,
            "download_url": s3_presign_get(key, expires=3600),
            "cached": True,
        })

    job_id = str(uuid.uuid4())
    start = time.time()
    try:
        png = render_screenshot_png(url)
        thumb_bytes, content_type = make_thumbnail(png)
        meta = {"url": url, "job_id": job_id}
        s3_put_object(key, thumb_bytes, content_type, meta)
        elapsed = time.time() - start
    except Exception as e:
        logger.exception("sync_failed url=%s", url)
        return jsonify({"error": str(e)}), 502

    if S3_ACL == "public-read" and PUBLIC_BASE_URL:
        public_url = PUBLIC_BASE_URL.rstrip("/") + "/" + key
        return jsonify({
            "status": "done",
            "job_id": job_id,
            "url": url,
            "s3_key": key,
            "public_url": public_url,
            "cached": False,
            "elapsed_seconds": round(elapsed, 3),
        })

    return jsonify({
        "status": "done",
        "job_id": job_id,
        "url": url,
        "s3_key": key,
        "download_url": s3_presign_get(key, expires=3600),
        "cached": False,
        "elapsed_seconds": round(elapsed, 3),
    })


def _janitor_loop() -> None:
    while True:
        time.sleep(60)
        now = time.time()
        with results_lock:
            to_del = []
            for job_id, r in results.items():
                created = r.get("created_at") or r.get("completed_at") or now
                if now - float(created) > max(DEDUP_TTL_SECONDS, 900):
                    to_del.append(job_id)
            for job_id in to_del:
                results.pop(job_id, None)


def main():
    if not S3_BUCKET:
        logger.warning("S3_BUCKET is not set; service will error on requests.")
    start_workers()
    threading.Thread(target=_janitor_loop, daemon=True).start()
    app.run(host=APP_HOST, port=APP_PORT, threaded=True)


if __name__ == "__main__":
    main()